$data_k = [
    "active" => [
        ["algo" => 426, "uuid" => "8af28a", "name" => "rsa-pss", "type" => "signature", "status" => "active", "title" => "RSA-PSS", "description_md" => "RSA-PSS (Probabilistic Signature Scheme) is the secure RSA signature scheme defined in RFC 8017 (PKCS#1 v2.2). Uses randomized PSS padding with MGF1 for provable security in the random oracle model.\n\nRSA-PSS is the recommended RSA signature scheme. Used in TLS 1.3 (required for certificate signatures), JWS PS256/PS384/PS512, PKIX certificates, and code signing. RSA-PKCS1v15 signatures are still accepted in X.509 but RSA-PSS is preferred for new designs.", "mental_model" => "Secure randomized RSA signature -- TLS 1.3 cert, JWS PS256, PKIX preferred.", "purpose" => ["rsa certificate signing", "tls 1.3 signatures", "jws ps256"], "good_for" => ["rsa-2048+ certificate signing", "tls 1.3 rsa signatures", "jws ps256/ps384/ps512"], "avoid_for" => ["post-quantum (use ml-dsa)", "rsa < 2048-bit"], "pros" => ["rfc 8017 standard", "provably secure", "tls 1.3 required", "jws ps256"], "cons" => ["quantum-vulnerable", "rsa key management complexity"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Fully broken by Shor's algorithm.", "post_quantum_status" => 1, "example" => ["scenario" => "TLS 1.3 RSA-PSS certificate signature", "input" => ["rsa_priv" => "2048-bit private key", "message" => "certificate TBS bytes"], "output" => ["signature" => "256-byte RSA-PSS signature"]], "flow" => ["PSS encode: emLen-byte padded message with random salt + MGF1", "RSA sign: sig = msg^d mod n", "verify: sig^e mod n then PSS decode"], "related" => ["rsa-pkcs1v15-sign", "ml-dsa-65", "ecdsa"]],
        ["algo" => 428, "uuid" => "8beea6", "name" => "ecdsa", "type" => "signature", "status" => "active", "title" => "ECDSA", "description_md" => "ECDSA (Elliptic Curve Digital Signature Algorithm) is the EC variant of DSA defined in FIPS 186. Uses a random nonce k for each signature; k reuse catastrophically reveals the private key.\n\nECDSA P-256 is the most widely deployed signature algorithm (TLS 1.2/1.3 certificates, HTTPS, JWT ES256, Bitcoin, Ethereum). Critically requires a unique random k per signature -- PlayStation 3 ECDSA hack (same k) revealed Sony's private key.", "mental_model" => "EC DSA -- TLS/JWT ES256/Bitcoin standard, catastrophic k-reuse vulnerability.", "purpose" => ["tls certificate signing", "jwt es256", "bitcoin transactions", "code signing"], "good_for" => ["tls p-256 certificates", "jwt es256/es384", "bitcoin/ethereum", "general signing"], "avoid_for" => ["post-quantum (use ml-dsa)", "deterministic needed (use det-ecdsa)"], "pros" => ["fips 186 standard", "universal support", "p-256 tls standard", "jwt es256"], "cons" => ["quantum-vulnerable", "k-reuse catastrophic", "use det-ecdsa or ed25519 instead"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Fully broken by Shor's algorithm.", "post_quantum_status" => 1, "example" => ["scenario" => "TLS P-256 certificate signature (JWT ES256)", "input" => ["priv_key" => "P-256 private key", "message" => "JWT header.payload"], "output" => ["signature" => "64-byte r||s"]], "flow" => ["k = secure random", "R = k*G, r = R.x mod n", "s = k^-1 * (hash(m) + r*priv) mod n", "sig = (r, s)"], "related" => ["det-ecdsa", "ed25519", "rsa-pss"]],
        ["algo" => 429, "uuid" => "682ae3", "name" => "det-ecdsa", "type" => "signature", "status" => "active", "title" => "Deterministic ECDSA", "description_md" => "Deterministic ECDSA (RFC 6979) derives the nonce k deterministically from the private key and message using HMAC-DRBG. Eliminates the catastrophic k-reuse vulnerability of standard ECDSA.\n\nRFC 6979 is the recommended way to implement ECDSA. Used in Bitcoin (libsecp256k1), Ethereum (go-ethereum), and most production ECDSA libraries. The deterministic k makes the signature deterministic but retains all ECDSA security properties.", "mental_model" => "ECDSA with RFC 6979 deterministic k -- eliminates catastrophic k-reuse, Bitcoin/Ethereum standard.", "purpose" => ["safe ecdsa without random k"], "good_for" => ["bitcoin/ethereum signing", "production ecdsa implementation", "deterministic reproducible sigs"], "avoid_for" => ["post-quantum (use ml-dsa)", "ed25519 simpler and safer"], "pros" => ["rfc 6979 standard", "eliminates k-reuse risk", "deterministic", "bitcoin/ethereum used"], "cons" => ["quantum-vulnerable", "ed25519 simpler for new designs"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Fully broken by Shor's algorithm.", "post_quantum_status" => 1, "example" => ["scenario" => "RFC 6979 deterministic ECDSA P-256", "input" => ["priv" => "P-256 private key", "message" => "data to sign"], "output" => ["sig" => "deterministic r||s"]], "flow" => ["k = HMAC-DRBG(priv_key, message_hash)", "R = k*G, r = R.x", "s = k^-1*(hash + r*priv) mod n"], "related" => ["ecdsa", "ed25519", "hmac"]],
        ["algo" => 430, "uuid" => "a23a6a", "name" => "ecdsa-recoverable", "type" => "signature", "status" => "active", "title" => "ECDSA Recoverable", "description_md" => "ECDSA recoverable signature includes a recovery byte (v) that allows recovering the public key from the signature. The 65-byte format (v, r, s) enables public key recovery without separately transmitting the public key.\n\nRecoverable ECDSA is used in Ethereum transaction signing (ecrecover opcode), Bitcoin message signing (BIP-137), and blockchain protocols where senders don't include their public key in every transaction.", "mental_model" => "ECDSA + recovery byte -- Ethereum ecrecover, public key recoverable from signature.", "purpose" => ["ethereum transaction signing", "blockchain pubkey recovery"], "good_for" => ["ethereum ecrecover", "bitcoin message signing", "blockchain protocols"], "avoid_for" => ["non-blockchain (extra complexity)"], "pros" => ["public key recoverable", "ethereum standard", "no pubkey transmission needed"], "cons" => ["quantum-vulnerable", "blockchain-specific niche"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Fully broken by Shor's algorithm.", "post_quantum_status" => 1, "example" => ["scenario" => "Ethereum transaction signature", "input" => ["priv" => "secp256k1 private key", "tx_hash" => "keccak256(RLP(tx))"], "output" => ["v" => "27 or 28", "r" => "32 bytes", "s" => "32 bytes"]], "flow" => ["det-ecdsa sign: (r, s)", "compute parity v from R.y", "output (v, r, s) 65 bytes"], "related" => ["ecdsa", "det-ecdsa", "secp256k1"]],
        ["algo" => 431, "uuid" => "6b1d26", "name" => "ed25519", "type" => "signature", "status" => "active", "title" => "Ed25519", "description_md" => "Ed25519 is the EdDSA (Edwards-curve Digital Signature Algorithm) signature scheme using Curve25519 (Twisted Edwards form), designed by Bernstein et al. (2011). Defined in RFC 8032.\n\nEd25519 is the recommended signature algorithm for new designs. Deterministic (no random nonce), constant-time, fast, resistant to side-channels. Used in OpenSSH (default key type), TLS 1.3, Signal Protocol, WireGuard, DNSSEC, JWT ES_256K... (as EdDSA). Ed25519 keys: 32-byte private, 32-byte public, 64-byte signature.", "mental_model" => "EdDSA Curve25519 -- recommended modern signature: OpenSSH, TLS 1.3, WireGuard.", "purpose" => ["modern signature scheme", "openssh", "tls 1.3", "wireguard"], "good_for" => ["openssh key signing", "tls 1.3", "signal", "wireguard", "jwt eddsa", "general signing"], "avoid_for" => ["post-quantum (use ml-dsa)", "fips compliance (use ecdsa p-256)"], "pros" => ["deterministic", "constant-time", "fast (65000 sig/sec)", "rfc 8032 standard", "32-byte keys"], "cons" => ["quantum-vulnerable", "not fips (use ecdsa for fips)"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Fully broken by Shor's algorithm. Transition to ML-DSA.", "post_quantum_status" => 1, "example" => ["scenario" => "OpenSSH Ed25519 host key signature", "input" => ["priv" => "32-byte seed", "message" => "ssh handshake data"], "output" => ["sig" => "64-byte signature"]], "flow" => ["deterministic nonce from H(priv_b || message)", "R = nonce * B", "S = (nonce + H(R||pubkey||message) * priv) mod l", "sig = R||S (64 bytes)"], "related" => ["ed448", "ecdsa", "det-ecdsa"]],
        ["algo" => 432, "uuid" => "9e490c", "name" => "ed448", "type" => "signature", "status" => "active", "title" => "Ed448", "description_md" => "Ed448 (Ed448-Goldilocks) is EdDSA on Curve448, providing 224-bit security. Defined in RFC 8032. Larger and slower than Ed25519 but higher security margin.\n\nEd448 provides 224-bit security (vs 128-bit for Ed25519). Used in TLS 1.3 and OpenSSH as a high-security alternative. 57-byte private key, 57-byte public key, 114-byte signature.", "mental_model" => "EdDSA Curve448 -- 224-bit security, higher-security Ed25519 alternative.", "purpose" => ["high-security 224-bit signature"], "good_for" => ["224-bit signature requirement", "tls 1.3 high security certs"], "avoid_for" => ["performance-sensitive (ed25519 faster)", "post-quantum (ml-dsa)"], "pros" => ["224-bit security", "rfc 8032 standard", "deterministic", "constant-time"], "cons" => ["slower than ed25519", "57-byte keys larger", "quantum-vulnerable"], "difficulty" => 1, "security" => 5, "quantum_impact" => "Fully broken by Shor's algorithm.", "post_quantum_status" => 1, "example" => ["scenario" => "Ed448 high-security signing", "input" => ["priv" => "57-byte seed", "message" => "data"], "output" => ["sig" => "114-byte signature"]], "flow" => ["same as ed25519 on curve448-goldilocks"], "related" => ["ed25519", "ecdsa", "x448"]],
        ["algo" => 433, "uuid" => "488146", "name" => "sr25519", "type" => "signature", "status" => "active", "title" => "sr25519", "description_md" => "sr25519 is a Schnorr signature scheme over Ristretto255 (sr = Schnorr Ristretto). Developed by Web3 Foundation (Parity/Substrate) for Polkadot and Substrate blockchains.\n\nsr25519 provides a cleaner Schnorr construction on Ristretto255 that avoids cofactor issues with Curve25519. Enables Schnorr signature aggregation and hierarchical key derivation (BIP32-like) for Substrate/Polkadot.", "mental_model" => "Schnorr on Ristretto255 -- Polkadot/Substrate blockchain signing with aggregation support.", "purpose" => ["polkadot/substrate signing", "schnorr ristretto255"], "good_for" => ["polkadot blockchain", "substrate accounts", "schnorr aggregation"], "avoid_for" => ["non-substrate (use ed25519)", "post-quantum (ml-dsa)"], "pros" => ["schnorr aggregation support", "ristretto255 cofactor-clean", "substrate/polkadot standard"], "cons" => ["blockchain-specific", "limited deployment outside substrate"], "difficulty" => 3, "security" => 5, "quantum_impact" => "Fully broken by Shor's algorithm.", "post_quantum_status" => 1, "example" => ["scenario" => "Polkadot substrate account signing", "input" => ["priv" => "sr25519 key pair", "message" => "substrate extrinsic"], "output" => ["sig" => "64-byte sr25519 signature"]], "flow" => ["merlin transcript", "ristretto255 nonce generation", "schnorr sign"], "related" => ["ed25519", "schnorr", "bls12-381-g1"]],
        ["algo" => 434, "uuid" => "07565c", "name" => "sm2-sign", "type" => "signature", "status" => "active", "title" => "SM2 Signature", "description_md" => "SM2 is a Chinese national standard elliptic curve signature scheme (GB/T 32918). Uses SM2 curve (256-bit), SM3 hash. Mandatory for Chinese government and financial systems.\n\nSM2 signature is required in China's national cryptographic standard (GM/T). Used in Chinese banking systems, e-government, TLS with GM cipher suites, digital certificates, and digital yuan. Different from ECDSA despite similar structure.", "mental_model" => "Chinese national EC signature standard -- SM2 curve + SM3 hash, required for China financial/gov.", "purpose" => ["chinese national standard signing"], "good_for" => ["china banking/e-government", "sm2 tls gm cipher suites", "digital yuan"], "avoid_for" => ["international (ecdsa p-256 or ed25519)"], "pros" => ["chinese national standard gb/t 32918", "required for china compliance", "256-bit ec security"], "cons" => ["china-specific", "limited non-china deployment"], "difficulty" => 3, "security" => 4, "quantum_impact" => "Quantum-vulnerable like ECDSA.", "post_quantum_status" => 1, "example" => ["scenario" => "China banking SM2 digital signature", "input" => ["priv" => "SM2 private key", "message" => "transaction data", "hash" => "SM3"], "output" => ["sig" => "(r, s) 64 bytes"]], "flow" => ["SM2 specific Z value computation", "hash = SM3(Z || message)", "ECDSA-like signing on SM2 curve"], "related" => ["ecdsa", "sm3", "sm4"]],
        ["algo" => 435, "uuid" => "9eb56e", "name" => "gost-r-34.10-2012", "type" => "signature", "status" => "active", "title" => "GOST R 34.10-2012", "description_md" => "GOST R 34.10-2012 is the Russian national standard for digital signatures (Strelets/Stribog). Uses GOST elliptic curves (256-bit and 512-bit variants). Replaces the earlier GOST R 34.10-2001.\n\nGOST R 34.10-2012 is mandatory for Russian government and classified systems. Used in Russian banking (SWIFT Russia), e-government, TLS with GOST cipher suites. The 512-bit variant provides double the classical security.", "mental_model" => "Russian national EC signature -- GOST 2012 curves, required for Russian gov/banking.", "purpose" => ["russian national standard signing"], "good_for" => ["russian gov/banking", "gost tls cipher suites", "russian e-government"], "avoid_for" => ["international (ecdsa or ed25519)"], "pros" => ["russian national standard", "512-bit variant", "required for russia compliance"], "cons" => ["russia-specific", "limited non-russia deployment"], "difficulty" => 3, "security" => 4, "quantum_impact" => "Quantum-vulnerable for 256-bit; 512-bit slightly better.", "post_quantum_status" => 1, "example" => ["scenario" => "Russian e-government GOST 2012 signature", "input" => ["priv" => "GOST 2012 512-bit private key", "message" => "document hash"], "output" => ["sig" => "64-byte GOST signature"]], "flow" => ["Stribog hash of message", "GOST R 34.10-2012 signing on GOST curves"], "related" => ["ecdsa", "gost-r-34.10-2001"]],
        ["algo" => 437, "uuid" => "a23a8d", "name" => "schnorr", "type" => "signature", "status" => "active", "title" => "Schnorr Signature", "description_md" => "Schnorr signature is a cryptographic signature scheme by Claus Schnorr (1989). Simpler, more provably secure, and more efficient than DSA/ECDSA. Supports natural signature aggregation (MuSig).\n\nSchnorr signatures are used in Bitcoin Taproot (BIP-340 secp256k1), Polkadot (sr25519), and many threshold signature protocols. BIP-340 specifies 64-byte Schnorr signatures on secp256k1 for Bitcoin.", "mental_model" => "Schnorr signature -- Bitcoin Taproot BIP-340, provable security, aggregation-friendly.", "purpose" => ["bitcoin taproot signing", "threshold signatures", "general schnorr"], "good_for" => ["bitcoin taproot bip-340", "musig aggregation", "threshold signatures"], "avoid_for" => ["post-quantum (ml-dsa)", "legacy compatibility (ecdsa)"], "pros" => ["provably secure", "64-byte compact", "aggregation support", "bitcoin taproot standard"], "cons" => ["quantum-vulnerable", "secp256k1-specific in bitcoin context"], "difficulty" => 2, "security" => 5, "quantum_impact" => "Fully broken by Shor's algorithm.", "post_quantum_status" => 1, "example" => ["scenario" => "Bitcoin Taproot BIP-340 Schnorr signature", "input" => ["priv" => "secp256k1 private key", "message" => "32-byte tagged hash"], "output" => ["sig" => "64-byte (R||s)"]], "flow" => ["nonce k from RFC 6979", "R = k*G", "e = H(R||P||message)", "s = k + e*priv mod n", "sig = R.x || s"], "related" => ["ecdsa", "musig", "musig2", "bls12-381-g1"]],
        ["algo" => 438, "uuid" => "96f270", "name" => "bbs", "type" => "signature", "status" => "active", "title" => "BBS Signatures", "description_md" => "BBS (Boneh-Boyen-Shacham) signatures are pairing-based signatures supporting selective disclosure of individual messages from a multi-message signature. Enable privacy-preserving credentials.\n\nBBS signatures are used in W3C Verifiable Credentials (VC), DIDs, and decentralized identity (DIF BBS+ specification). Enable zero-knowledge proofs: prove you hold a valid credential without revealing all attributes.", "mental_model" => "Pairing BLS12-381 multi-message sig with selective disclosure -- W3C Verifiable Credentials, DID.", "purpose" => ["selective disclosure credentials", "verifiable credentials w3c", "zk-snark credentials"], "good_for" => ["w3c vc selective disclosure", "did credentials", "privacy-preserving identity"], "avoid_for" => ["simple signing (ed25519 faster)", "post-quantum (not pq)"], "pros" => ["selective disclosure", "w3c vc standard", "zk proof compatibility", "bls12-381 based"], "cons" => ["pairing-based (quantum-vulnerable)", "complex", "performance overhead"], "difficulty" => 4, "security" => 5, "quantum_impact" => "Pairing-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "W3C VC selective disclosure credential", "input" => ["messages" => ["name", "dob", "country"], "priv" => "BLS12-381 key"], "output" => ["sig" => "bbs+ signature over all messages"]], "flow" => ["keygen on BLS12-381 G2", "sign multiple messages with commitment", "derive proof revealing subset without others"], "related" => ["bls12-381-g1", "bls12-381-g2", "ed25519"]],
        ["algo" => 439, "uuid" => "5beedf", "name" => "bls12-381-g1", "type" => "signature", "status" => "active", "title" => "BLS Signature G1", "description_md" => "BLS (Boneh-Lynn-Shacham) signatures on BLS12-381 curve using G1 for signatures and G2 for public keys. BLS signatures support aggregation: N signatures on different messages can be aggregated into a single constant-size signature verifiable with one pairing.\n\nBLS G1 signatures (96-byte sig, 48-byte pubkey) are used in Ethereum 2.0 (Proof of Stake) for validator attestations, Zcash, Filecoin, and many PoS blockchains. IETF draft-irtf-cfrg-bls-signature.", "mental_model" => "BLS12-381 G1 signature -- Ethereum 2.0 PoS validator attestation, signature aggregation.", "purpose" => ["bls aggregated signatures", "ethereum 2.0 pos", "validator attestations"], "good_for" => ["ethereum 2.0 validator sigs", "filecoin", "zcash", "pos blockchain"], "avoid_for" => ["post-quantum (not pq)", "non-pairing curves"], "pros" => ["aggregation: n sigs -> 1 sig", "48-byte pubkey", "96-byte sig", "ethereum pos standard"], "cons" => ["pairing cost", "quantum-vulnerable", "bls12-381 specific"], "difficulty" => 3, "security" => 5, "quantum_impact" => "Pairing-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Ethereum 2.0 validator attestation", "input" => ["priv" => "BLS12-381 private scalar", "message" => "beacon block hash"], "output" => ["sig" => "96-byte G1 signature"]], "flow" => ["hash message to G1 point", "sig = priv * H(msg)", "verify: e(sig, G2) = e(H(msg), pub_G2)"], "related" => ["bls12-381-g2", "bbs", "bls-aggregate"]],
        ["algo" => 440, "uuid" => "31f7b5", "name" => "bls12-381-g2", "type" => "signature", "status" => "active", "title" => "BLS Signature G2", "description_md" => "BLS signatures on BLS12-381 using G2 for signatures and G1 for public keys. 192-byte signatures, 48-byte public keys. Different from G1 variant in signature/pubkey point locations.\n\nBLS G2 variant is used in some Ethereum applications and Zcash Sapling. The trade-off: G2 sigs (192 bytes) vs G1 sigs (96 bytes) depending on whether aggregating pubkeys or signatures is the priority.", "mental_model" => "BLS12-381 G2 signature -- 192-byte sigs, G2 signatures with G1 public keys.", "purpose" => ["bls signature with g2 sigs"], "good_for" => ["pubkey aggregation priority", "zcash sapling", "g2 sig bls"], "avoid_for" => ["ethereum pos (uses g1 sigs)", "post-quantum"], "pros" => ["g1 pubkey aggregation", "bls12-381 standard"], "cons" => ["192-byte sigs larger than g1 variant", "quantum-vulnerable"], "difficulty" => 3, "security" => 5, "quantum_impact" => "Pairing-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "BLS G2 signature", "input" => ["priv" => "BLS12-381 key", "message" => "data"], "output" => ["sig" => "192-byte G2 point"]], "flow" => ["hash to G2 point", "sig = priv * H(msg) in G2", "verify via pairing G1 pub"], "related" => ["bls12-381-g1", "bbs"]],
    ],
    "legacy" => [
        ["algo" => 425, "uuid" => "427734", "name" => "rsa-pkcs1v15-sign", "type" => "signature", "status" => "legacy", "title" => "RSA-PKCS#1v1.5 Sig", "description_md" => "RSA-PKCS#1v1.5 signature is the original RSA signature padding scheme. More brittle than RSA-PSS due to deterministic padding, but widely deployed in legacy TLS certificates, PGP, and S/MIME.\n\nRSA-PKCS1v15 signatures are still accepted in TLS 1.2 certificates and remain widely deployed. However, some variant attacks (e.g., Bleichenbacher on signature verification in buggy implementations) exist. New deployments should use RSA-PSS or Ed25519.", "mental_model" => "RSA PKCS#1 v1.5 signature -- legacy TLS certs/PGP, use RSA-PSS for new.", "purpose" => ["legacy tls certificate signing", "pgp rsa signatures"], "good_for" => ["legacy tls 1.2 rsa cert compatibility", "pgp legacy"], "avoid_for" => ["new certificates (rsa-pss)", "post-quantum (ml-dsa)"], "pros" => ["universal legacy support", "x.509 pkcs#1v15 certs ubiquitous"], "cons" => ["deterministic padding more brittle", "use rsa-pss for new"], "difficulty" => 2, "security" => 3, "quantum_impact" => "Fully broken by Shor's algorithm.", "post_quantum_status" => 1, "example" => ["scenario" => "Legacy TLS 1.2 RSA certificate", "input" => ["priv" => "2048-bit RSA key", "digest" => "SHA-256(TBS cert)"], "output" => ["sig" => "256-byte PKCS#1v1.5 signature"]], "flow" => ["DER encode DigestInfo", "PKCS1v15 pad to modulus length", "sig = pad^d mod n"], "related" => ["rsa-pss", "ecdsa", "ml-dsa-65"]],
        ["algo" => 427, "uuid" => "1e49f3", "name" => "dsa", "type" => "signature", "status" => "legacy", "title" => "DSA", "description_md" => "DSA (Digital Signature Algorithm) is the NIST-standard signature algorithm from FIPS 186 (1991). Uses a DSA group (prime p, subgroup prime q, generator g) for modular arithmetic signatures.\n\nDSA was the US government standard before ECDSA. Retired in FIPS 186-5 (2023) -- DSA is no longer approved for new key generation. Replaced by ECDSA and EdDSA. Same catastrophic k-reuse vulnerability as ECDSA.", "mental_model" => "Original NIST DSA 1991 -- retired in FIPS 186-5 2023, use ECDSA or Ed25519.", "purpose" => ["legacy dsa digital signatures"], "good_for" => ["legacy dsa compatibility"], "avoid_for" => ["any new use (fips 186-5 retired dsa)", "post-quantum (ml-dsa)"], "pros" => ["fips 186 original standard"], "cons" => ["retired fips 186-5 2023", "k-reuse catastrophic", "slow vs ecdsa", "no new key gen"], "difficulty" => 3, "security" => 2, "quantum_impact" => "Fully broken by Shor's algorithm.", "post_quantum_status" => 1, "example" => ["scenario" => "Legacy DSA-2048 signature", "input" => ["priv" => "DSA private key", "message" => "data"], "output" => ["sig" => "(r, s) 40-byte SHA-1/SHA-256"]], "flow" => ["k = random nonce (catastrophic if reused)", "r = (g^k mod p) mod q", "s = k^-1(hash(m) + x*r) mod q"], "related" => ["ecdsa", "ed25519", "rsa-pkcs1v15-sign"]],
        ["algo" => 436, "uuid" => "5c3e1c", "name" => "gost-r-34.10-2001", "type" => "signature", "status" => "legacy", "title" => "GOST R 34.10-2001", "description_md" => "GOST R 34.10-2001 is the previous Russian national standard for digital signatures, superseded by GOST R 34.10-2012. Based on elliptic curves over 256-bit prime fields.\n\nGOST R 34.10-2001 was the Russian ECDSA equivalent. Superseded by the 2012 standard. Legacy systems still use it but migration to GOST 2012 is mandated.", "mental_model" => "Previous Russian EC signature standard -- superseded by GOST R 34.10-2012.", "purpose" => ["legacy russian signing standard"], "good_for" => ["legacy russian system compatibility"], "avoid_for" => ["new systems (use gost 2012)"], "pros" => ["russian legacy support"], "cons" => ["superseded by gost 2012", "legacy only"], "difficulty" => 3, "security" => 3, "quantum_impact" => "Quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Legacy GOST 2001 signature", "input" => ["priv" => "gost 2001 key", "hash" => "gost-r-34.11-94 hash"], "output" => ["sig" => "512-bit sig"]], "flow" => ["gost 2001 ec ops"], "related" => ["gost-r-34.10-2012", "ecdsa"]],
        ["algo" => 441, "uuid" => "755834", "name" => "rainbow", "type" => "signature", "status" => "legacy", "title" => "Rainbow (BROKEN)", "description_md" => "Rainbow was a multivariate post-quantum signature scheme and NIST PQC finalist. Based on multilayer Oil-and-Vinegar (UOV) polynomials. Completely broken by Ward Beullens in February 2022 using a classical attack on a laptop.\n\nRainbow was a NIST PQC Round 3 finalist that was broken before standardization. The attack exploits the rainbow structure. All Rainbow parameters are broken. Use ML-DSA instead.", "mental_model" => "Rainbow PQ signature -- NIST Round 3 finalist COMPLETELY BROKEN by Beullens 2022.", "purpose" => ["historical: broken pq signature"], "good_for" => ["pqc attack history study"], "avoid_for" => ["any use (completely broken)"], "pros" => ["historical interest only"], "cons" => ["completely broken by classical attack (beullens 2022)", "do not use"], "difficulty" => 5, "security" => 1, "quantum_impact" => "Broken classically.", "post_quantum_status" => 1, "example" => ["scenario" => "Rainbow - BROKEN (do not use)", "input" => [], "output" => ["warning" => "COMPLETELY BROKEN - Beullens 2022"]], "flow" => ["broken: intermediate layer attack recovers key"], "related" => ["ml-dsa-65", "uov"]],
        ["algo" => 442, "uuid" => "f0a99a", "name" => "ge-mss", "type" => "signature", "status" => "legacy", "title" => "GeMSS", "description_md" => "GeMSS (Great Multivariate Short Signature) is a multivariate post-quantum signature scheme that was a NIST PQC alternate candidate. Based on Hidden Field Equations (HFE) with minus and vinegar modifications.\n\nGeMSS was designed for extremely short signatures (33-byte signatures!) but requires huge public keys (1-3 MB) and slow signing/verification. Weakened during NIST analysis -- no longer competitive.", "mental_model" => "Multivariate HFE short signature -- tiny 33-byte sigs but 1-3MB public key, NIST weakened.", "purpose" => ["short-signature pq (historically)"], "good_for" => ["pqc multivariate history"], "avoid_for" => ["any production (weakened, huge pk)"], "pros" => ["33-byte signature size"], "cons" => ["1-3MB public key", "weakened by nist analysis", "slow"], "difficulty" => 5, "security" => 2, "quantum_impact" => "PQ but weakened.", "post_quantum_status" => 2, "example" => ["scenario" => "GeMSS signature (historical)", "input" => ["pk" => "1MB+ public key"], "output" => ["sig" => "33 bytes"]], "flow" => ["hfe multivariate polynomial solve"], "related" => ["ml-dsa-65", "uov", "mayo"]],
    ],
    "new" => [
        ["algo" => 443, "uuid" => "6b6edd", "name" => "ecdsa-secp256k1", "type" => "signature", "status" => "new", "title" => "ECDSA secp256k1", "description_md" => "ECDSA on secp256k1 is the specific instantiation used in Bitcoin, Ethereum, and most cryptocurrencies. secp256k1 is the Koblitz curve y^2 = x^3 + 7 over a 256-bit prime field.\n\nsecp256k1 ECDSA is the Bitcoin and Ethereum signing standard. Different from NIST P-256 (secp256r1). Has better constant-time properties than P-256 for some implementations. Being replaced by Schnorr (BIP-340) in Bitcoin Taproot.", "mental_model" => "ECDSA on Bitcoin/Ethereum secp256k1 Koblitz curve -- being replaced by Schnorr Taproot.", "purpose" => ["bitcoin/ethereum transaction signing"], "good_for" => ["bitcoin legacy p2pkh/p2sh", "ethereum transactions", "secp256k1 signing"], "avoid_for" => ["new bitcoin (use schnorr taproot)", "post-quantum (ml-dsa)"], "pros" => ["bitcoin/ethereum standard", "secp256k1 efficient koblitz"], "cons" => ["quantum-vulnerable", "being replaced by schnorr in bitcoin"], "difficulty" => 2, "security" => 4, "quantum_impact" => "Fully broken by Shor's algorithm.", "post_quantum_status" => 1, "example" => ["scenario" => "Bitcoin legacy transaction signing", "input" => ["priv" => "secp256k1 private key", "tx_hash" => "SHA256d(tx)"], "output" => ["sig" => "DER encoded (r, s)"]], "flow" => ["det-ecdsa with rfc 6979 on secp256k1"], "related" => ["ecdsa", "schnorr", "det-ecdsa"]],
        ["algo" => 444, "uuid" => "351b65", "name" => "rsa-fdh", "type" => "signature", "status" => "new", "title" => "RSA-FDH", "description_md" => "RSA-FDH (Full Domain Hash) is a theoretically tight RSA signature scheme that hashes the message to the full RSA modulus domain before signing. Provably secure in the random oracle model.\n\nRSA-FDH is primarily academic/theoretical -- it requires a hash that maps to the full modulus (not standard SHA-256). RSA-PSS is the practical alternative. Historically important as the first provably secure RSA signature scheme.", "mental_model" => "Theoretically tight RSA-FDH -- full domain hash, academic/historical, RSA-PSS is practical.", "purpose" => ["academic rsa full domain hash"], "good_for" => ["rsa signature theory study"], "avoid_for" => ["production (use rsa-pss)"], "pros" => ["tight security reduction", "provably secure rom"], "cons" => ["impractical full domain hash", "rsa-pss is the standard"], "difficulty" => 3, "security" => 4, "quantum_impact" => "RSA quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "RSA-FDH academic", "input" => ["priv" => "RSA key", "msg" => "message"], "output" => ["sig" => "H_full_domain(msg)^d mod n"]], "flow" => ["hash message to element in ZN*", "sig = hash^d mod n"], "related" => ["rsa-pss", "rsa-pkcs1v15-sign"]],
        ["algo" => 445, "uuid" => "11a9cf", "name" => "kcdsa", "type" => "signature", "status" => "new", "title" => "KCDSA", "description_md" => "KCDSA (Korean Certificate-based Digital Signature Algorithm) is the South Korean national standard digital signature algorithm. Based on discrete logarithm similar to DSA but with different structure.\n\nKCDSA is mandatory for South Korean government systems and financial institutions. Standardized in TTAS.KO-12.0001.", "mental_model" => "South Korean national DSA standard -- required for Korean gov/financial systems.", "purpose" => ["korean national digital signature"], "good_for" => ["korean government/banking systems"], "avoid_for" => ["international (use ecdsa or ed25519)"], "pros" => ["korean national standard", "dlp-based signature"], "cons" => ["korea-specific", "dlp quantum-vulnerable"], "difficulty" => 3, "security" => 3, "quantum_impact" => "DLP quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Korean gov KCDSA signature", "input" => ["priv" => "KCDSA private key", "message" => "document"], "output" => ["sig" => "KCDSA signature"]], "flow" => ["kcdsa group ops", "dlp-based sign/verify"], "related" => ["dsa", "ecdsa"]],
        ["algo" => 446, "uuid" => "534730", "name" => "ecgdsa", "type" => "signature", "status" => "new", "title" => "ECGDSA", "description_md" => "ECGDSA (Elliptic Curve German Digital Signature Algorithm) is the German standard EC signature scheme defined in BSI TR-03111. Used in German government applications and eID cards.\n\nECGDSA differs from ECDSA in the message-nonce combination step. Used in German ePassport (eID), nPA (neuer Personalausweis) applications.", "mental_model" => "German EC signature standard -- BSI TR-03111, German eID/nPA cards.", "purpose" => ["german eid card signatures"], "good_for" => ["german eid npa", "bsi tr-03111 compliance"], "avoid_for" => ["international (use ecdsa)"], "pros" => ["bsi tr-03111 german standard", "german eid"], "cons" => ["germany-specific", "limited non-german use"], "difficulty" => 3, "security" => 4, "quantum_impact" => "Quantum-vulnerable like ECDSA.", "post_quantum_status" => 1, "example" => ["scenario" => "German eID card signature", "input" => ["priv" => "ECGDSA P-256 key", "message" => "document hash"], "output" => ["sig" => "ECGDSA signature"]], "flow" => ["bsi tr-03111 ecdsa variant", "different message-nonce combination"], "related" => ["ecdsa", "eckdsa"]],
        ["algo" => 447, "uuid" => "8c4742", "name" => "eckdsa", "type" => "signature", "status" => "new", "title" => "ECKDSA", "description_md" => "ECKDSA (Elliptic Curve KCDSA) is the EC variant of KCDSA, the Korean Certificate-based Digital Signature Algorithm. Standardized in TTAS.KO-12.0001.\n\nECKDSA is used in Korean PKI systems and smart cards for EC-based equivalent of KCDSA.", "mental_model" => "EC variant of Korean KCDSA -- Korean PKI EC signature.", "purpose" => ["korean ec signature"], "good_for" => ["korean pki ec signing"], "avoid_for" => ["international (ecdsa/ed25519)"], "pros" => ["korean ec standard", "smaller keys than kcdsa"], "cons" => ["korea-specific", "quantum-vulnerable"], "difficulty" => 3, "security" => 4, "quantum_impact" => "EC quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Korean PKI EC signature", "input" => ["priv" => "ECKDSA EC key", "hash" => "document hash"], "output" => ["sig" => "ECKDSA signature"]], "flow" => ["ec kcdsa ops on elliptic curve"], "related" => ["kcdsa", "ecdsa"]],
        ["algo" => 448, "uuid" => "e81671", "name" => "musig", "type" => "signature", "status" => "new", "title" => "MuSig", "description_md" => "MuSig is an interactive multi-signature Schnorr scheme by Maxwell, Poelstra, Seurin, and Wuille (2018). Aggregates n public keys and n signatures into a single key+signature indistinguishable from a regular Schnorr signature.\n\nMuSig is used in Bitcoin for n-of-n multisig that looks like a single key (privacy/efficiency). Requires 3 rounds of interaction. Superseded by MuSig2 which requires only 2 rounds.", "mental_model" => "3-round n-of-n Schnorr aggregation -- Bitcoin multisig privacy, superseded by MuSig2.", "purpose" => ["n-of-n schnorr multisig aggregation"], "good_for" => ["bitcoin n-of-n multisig", "schnorr aggregation", "threshold privacy"], "avoid_for" => ["3 rounds required (use musig2 for 2-round)"], "pros" => ["aggregated key looks like single key", "schnorr standard", "bitcoin privacy"], "cons" => ["3-round interaction", "musig2 preferred (2-round)", "quantum-vulnerable"], "difficulty" => 4, "security" => 5, "quantum_impact" => "Schnorr quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Bitcoin 2-of-2 MuSig multisig", "input" => ["priv1" => "key 1", "priv2" => "key 2", "message" => "tx hash"], "output" => ["agg_sig" => "single Schnorr sig"]], "flow" => ["round 1: exchange nonce commitments", "round 2: exchange nonces", "round 3: exchange partial sigs", "combine partial sigs"], "related" => ["musig2", "schnorr", "bls-aggregate"]],
        ["algo" => 449, "uuid" => "c1b7a1", "name" => "musig2", "type" => "signature", "status" => "new", "title" => "MuSig2", "description_md" => "MuSig2 is an improved interactive multi-signature Schnorr scheme by Nick, Ruffing, and Seurin (2020). Reduces MuSig's 3 rounds to 2 rounds while maintaining security.\n\nMuSig2 is the current standard for Bitcoin n-of-n multisig with aggregation. BIP-327 specifies MuSig2 for Bitcoin. Used in Lightning Network and Taproot multi-party signing.", "mental_model" => "2-round n-of-n Schnorr aggregation -- BIP-327, Bitcoin Lightning Network, Taproot multisig.", "purpose" => ["2-round schnorr n-of-n multisig"], "good_for" => ["bitcoin bip-327 multisig", "lightning network", "taproot musig2"], "avoid_for" => ["post-quantum (ml-dsa)"], "pros" => ["2-round (vs 3 in musig)", "bip-327 bitcoin standard", "aggregated key privacy"], "cons" => ["quantum-vulnerable", "interactive 2 rounds still needed"], "difficulty" => 4, "security" => 5, "quantum_impact" => "Schnorr quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Bitcoin BIP-327 MuSig2 Taproot multisig", "input" => ["keys" => ["priv1", "priv2", "priv3"], "message" => "taproot tx hash"], "output" => ["agg_sig" => "64-byte Schnorr sig"]], "flow" => ["round 1: exchange nonce pairs", "round 2: exchange partial sigs", "combine partial sigs"], "related" => ["musig", "schnorr", "bls-aggregate"]],
        ["algo" => 450, "uuid" => "74c1d3", "name" => "bls-aggregate", "type" => "signature", "status" => "new", "title" => "BLS Aggregated Signatures", "description_md" => "BLS aggregated signatures allow N BLS signatures to be combined into a single constant-size aggregate signature. The aggregate can be verified against all N messages and N public keys with a single pairing.\n\nBLS aggregation is used in Ethereum 2.0 for combining thousands of validator attestations per slot, reducing bandwidth. Also used in Zcash, Filecoin, and PoS blockchains. IETF draft-irtf-cfrg-bls-signature.", "mental_model" => "BLS N-signature aggregation -- Ethereum 2.0 thousands of validator sigs -> 1 sig.", "purpose" => ["bls signature aggregation"], "good_for" => ["ethereum 2.0 attestation aggregation", "validator committee sigs", "bandwidth reduction"], "avoid_for" => ["post-quantum (pairing-based)", "small n (overhead not worth it)"], "pros" => ["n sigs -> single sig", "constant-size aggregate", "ethereum pos standard"], "cons" => ["pairing computation cost", "quantum-vulnerable"], "difficulty" => 3, "security" => 5, "quantum_impact" => "Pairing-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Ethereum 2.0 aggregate 128 attestations", "input" => ["sigs" => ["96-byte G1 sig 1", "..."], "pubs" => ["48-byte G2 pub 1", "..."]], "output" => ["agg_sig" => "single 96-byte sig"]], "flow" => ["aggregate sig = sig_1 + sig_2 + ... + sig_n (G1 addition)", "verify: e(agg, G2) = product(e(H(msg_i), pub_i))"], "related" => ["bls12-381-g1", "musig2", "schnorr"]],
        ["algo" => 451, "uuid" => "65600f", "name" => "rsa-blind-sig", "type" => "signature", "status" => "new", "title" => "RSA Blind Signature", "description_md" => "RSA blind signatures allow a user to get a message signed by a signer without the signer learning the message content. The user blinds the message, gets it signed, then unblinds the signature.\n\nRSA blind signatures are used in privacy-preserving digital cash (eCash by Chaum, 1983), anonymous credentials, and recently in Privacy Pass (RFC 9578) and Apple Private Access Tokens.", "mental_model" => "RSA signature where signer can't see the message -- Chaum eCash, Apple Private Access Tokens.", "purpose" => ["anonymous credentials", "privacy pass", "digital cash"], "good_for" => ["privacy pass rfc 9578", "anonymous ecash", "apple private access tokens"], "avoid_for" => ["standard signing (ed25519/ecdsa)"], "pros" => ["signer unlinkability", "privacy pass standard", "anonymous credentials"], "cons" => ["rsa quantum-vulnerable", "complex blind factor management"], "difficulty" => 3, "security" => 4, "quantum_impact" => "RSA quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Privacy Pass anonymous token issuance", "input" => ["message" => "token request", "blinding_factor" => "r"], "output" => ["blind_sig" => "H(m*r^e)^d = blind signature"]], "flow" => ["blind: m' = m * r^e mod n", "signer: sig' = m'^d mod n", "unblind: sig = sig' * r^-1 mod n"], "related" => ["bls-blind-sig", "rsa-pss"]],
        ["algo" => 452, "uuid" => "eaf566", "name" => "bls-blind-sig", "type" => "signature", "status" => "new", "title" => "BLS Blind Signature", "description_md" => "BLS blind signatures use the BLS signature scheme to create unlinkable signatures. The signer signs a blinded message and the requester unblinds to get the final signature.\n\nBLS blind signatures are more efficient than RSA blind signatures for some batch scenarios. Used in privacy-preserving credential systems and anonymous token protocols.", "mental_model" => "BLS pairing blind signature -- anonymous credentials, more efficient than RSA blind.", "purpose" => ["bls-based anonymous credentials"], "good_for" => ["anonymous bls credentials", "batch blind signing"], "avoid_for" => ["simple anonymous creds (privacy pass uses rsa)"], "pros" => ["bls aggregation compatible", "efficient pairing-based"], "cons" => ["pairing quantum-vulnerable", "complex"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Pairing-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "BLS blind signature anonymous credential", "input" => ["message_blinded" => "blinded G1 point", "priv" => "BLS key"], "output" => ["blind_sig" => "BLS signed blinded point"]], "flow" => ["blind: m' = m + r*G1", "sign: sig' = priv * m'", "unblind: sig = sig' - r*priv*G1"], "related" => ["bls12-381-g1", "rsa-blind-sig", "bbs"]],
        ["algo" => 453, "uuid" => "130f1f", "name" => "cryptonote-ring-sig", "type" => "signature", "status" => "new", "title" => "CryptoNote Ring Sig", "description_md" => "CryptoNote ring signatures are used in Monero for transaction anonymity. A ring signature proves a message was signed by one of a set of public keys without revealing which one.\n\nCryptoNote ring signatures are used in Monero (XMR) to hide the sender among a ring of decoys. Every Monero transaction includes a ring signature making the true spender indistinguishable from ring members.", "mental_model" => "Monero sender-anonymous ring signature -- signer hidden in ring of decoys.", "purpose" => ["monero sender anonymity"], "good_for" => ["monero xmr ring signatures", "sender anonymity in blockchain"], "avoid_for" => ["general signing (ed25519)", "post-quantum"], "pros" => ["sender anonymity", "monero standard", "blockchain privacy"], "cons" => ["large signature size (scales with ring)", "quantum-vulnerable", "monero-specific"], "difficulty" => 4, "security" => 4, "quantum_impact" => "ED25519-based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Monero ring-size-11 transaction", "input" => ["ring" => "11 public keys", "priv" => "true signer key", "message" => "tx hash"], "output" => ["ring_sig" => "ring signature hiding true signer"]], "flow" => ["pick ring of decoys", "compute signature linkable to one of ring members", "tag prevents double spend"], "related" => ["mlsag", "clsag", "ed25519"]],
        ["algo" => 454, "uuid" => "afba3a", "name" => "mlsag", "type" => "signature", "status" => "new", "title" => "MLSAG", "description_md" => "MLSAG (Multilayer Linkable Spontaneous Anonymous Group signature) is the ring signature scheme used in older Monero (before CLSAG). Signs multiple inputs simultaneously.\n\nMLSAG was Monero's ring signature standard before CLSAG replacement in 2020. Larger than CLSAG but historically significant. Provides sender anonymity and double-spend prevention via key images.", "mental_model" => "Monero pre-2020 multi-input ring signature -- replaced by CLSAG for smaller size.", "purpose" => ["monero pre-2020 ring signatures"], "good_for" => ["monero historical/legacy"], "avoid_for" => ["new monero (use clsag)", "general signing (ed25519)"], "pros" => ["multi-input ring signature", "key image double-spend prevention"], "cons" => ["replaced by clsag (smaller)", "quantum-vulnerable"], "difficulty" => 4, "security" => 4, "quantum_impact" => "ED25519 based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Monero pre-CLSAG transaction", "input" => ["ring" => "decoy ring", "inputs" => "multiple UTXOs"], "output" => ["mlsag" => "ring sig over multiple inputs"]], "flow" => ["ring sig per input key tuple", "key images prevent double spend"], "related" => ["clsag", "cryptonote-ring-sig"]],
        ["algo" => 455, "uuid" => "5a2e96", "name" => "clsag", "type" => "signature", "status" => "new", "title" => "CLSAG", "description_md" => "CLSAG (Concise Linkable Spontaneous Anonymous Group signature) replaced MLSAG in Monero (October 2020). Provides the same privacy guarantees with ~25% smaller signatures.\n\nCLSAG is current Monero ring signature standard. Smaller and faster verification than MLSAG. Provides sender anonymity with key image linkability to prevent double spending.", "mental_model" => "Current Monero ring signature standard -- 25% smaller than MLSAG, same privacy.", "purpose" => ["current monero ring signatures"], "good_for" => ["monero current standard ring sig"], "avoid_for" => ["general signing", "post-quantum"], "pros" => ["25% smaller than mlsag", "current monero standard", "fast verify"], "cons" => ["quantum-vulnerable", "monero-specific"], "difficulty" => 4, "security" => 4, "quantum_impact" => "ED25519 based; quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Monero CLSAG current transaction", "input" => ["ring" => "ring-11 decoys", "priv" => "spend key"], "output" => ["clsag" => "concise ring sig"]], "flow" => ["concise ring sig construction", "key image for double-spend prevention", "smaller than mlsag via coefficient optimization"], "related" => ["mlsag", "cryptonote-ring-sig"]],
        ["algo" => 456, "uuid" => "15cddd", "name" => "group-sig", "type" => "signature", "status" => "new", "title" => "Group Signature", "description_md" => "Group signatures allow any member of a group to sign on behalf of the group, with a trusted manager able to reveal the signer if needed. Provides anonymity to outsiders but accountability to the group manager.\n\nGroup signatures are used in privacy-preserving attestation (Intel SGX EPID attestation), trusted platform module (TPM) direct anonymous attestation (DAA), and anonymous employee authentication.", "mental_model" => "Group member signs anonymously, manager can de-anonymize -- SGX EPID, TPM DAA.", "purpose" => ["anonymous group attestation"], "good_for" => ["intel sgx epid attestation", "tpm daa", "anonymous group auth"], "avoid_for" => ["full anonymity (manager can reveal)", "general signing (ed25519)"], "pros" => ["anonymous within group", "accountable to manager", "sgx/tpm standard"], "cons" => ["manager trusted de-anonymizer", "complex setup", "quantum-vulnerable"], "difficulty" => 4, "security" => 4, "quantum_impact" => "Pairing-based constructions quantum-vulnerable.", "post_quantum_status" => 1, "example" => ["scenario" => "Intel SGX EPID anonymous attestation", "input" => ["group_key" => "sgx group public key", "priv" => "device private member key"], "output" => ["group_sig" => "anonymous sig verifiable by group pk"]], "flow" => ["group setup by manager", "member sign with group key", "verify against group pk (anonymous)", "manager open signature to reveal member"], "related" => ["bbs", "bls12-381-g1", "ed25519"]],
    ]
];
